function ec_row($id){global $db;return $db->fetch("SELECT c.*,e.employee_no,e.full_name,e.employment_status,d.nm_dept,j.job_title_code,j.job_title_name,p.position_code,p.position_name,cs.structure_code,cs.structure_name,wl.location_code,wl.location_name,ap.employee_no approved_no,ap.full_name approved_name,pc.contract_no previous_contract_no FROM erp_employee_contract c JOIN erp_employee_master e ON e.id=c.employee_id LEFT JOIN dept d ON d.kd_dept=c.department_code LEFT JOIN erp_job_title j ON j.id=c.job_title_id LEFT JOIN erp_position p ON p.id=c.position_id LEFT JOIN erp_company_structure cs ON cs.id=c.company_structure_id LEFT JOIN erp_work_location wl ON wl.id=c.work_location_id LEFT JOIN erp_employee_master ap ON ap.id=c.approved_by_employee_id LEFT JOIN erp_employee_contract pc ON pc.id=c.previous_contract_id WHERE c.id=? LIMIT 1",array((int)$id));}
