function ec_rows($from,$to,$type,$status,$approval,$dept,$kw){global $db;$w=" WHERE c.contract_start<=? AND COALESCE(c.contract_end,'9999-12-31')>=? ";$p=array($to,$from);if($type!==''){$w.=" AND c.contract_type=? ";$p[]=$type;}if($status!==''){$w.=" AND c.contract_status=? ";$p[]=$status;}if($approval!==''){$w.=" AND c.approval_status=? ";$p[]=$approval;}if($dept!==''){$w.=" AND c.department_code=? ";$p[]=$dept;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (c.contract_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR j.job_title_code LIKE ? OR j.job_title_name LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}return $db->query("SELECT c.*,e.employee_no,e.full_name,d.nm_dept,j.job_title_code,j.job_title_name,p.position_code,p.position_name,wl.location_code,wl.location_name,ap.employee_no approved_no,ap.full_name approved_name FROM erp_employee_contract c JOIN erp_employee_master e ON e.id=c.employee_id LEFT JOIN dept d ON d.kd_dept=c.department_code LEFT JOIN erp_job_title j ON j.id=c.job_title_id LEFT JOIN erp_position p ON p.id=c.position_id LEFT JOIN erp_work_location wl ON wl.id=c.work_location_id LEFT JOIN erp_employee_master ap ON ap.id=c.approved_by_employee_id $w ORDER BY c.contract_start DESC,c.contract_no DESC",$p);}
