  if($id>0){if(!$db->fetch("SELECT id FROM erp_employee_contract WHERE id=? LIMIT 1",array($id)))ec_json('error','Employee Contract tidak ditemukan.');$ok=$db->update('erp_employee_contract',$data,'id',$id);}else{$data['created_by']=$username;$ok=$db->insert('erp_employee_contract',$data);$id=$db->last_insert_id();}
  if(!$ok)ec_json('error',$db->getErrorMessage()?:'Employee Contract gagal disimpan.');if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Employee Contract '.$no.' pada '.date('Y-m-d H:i:s'),$username);ec_json('good','Employee Contract berhasil disimpan.',array('id'=>$id));
